mapper.select:
SELECT *
FROM attendance_record
WHERE schedule_id = #{scheduleId}
  AND student_id = #{studentId}
  AND attendance_date = #{attendanceDate}
LIMIT 1

mapper.update:
UPDATE attendance_record
SET status = #{status},
    signed_at = #{signedAt}
WHERE id = #{id}

UPDATE attendance_record
SET status = #{status}
WHERE id = #{id}

mapper.select:
SELECT attendance_date AS attendanceDate,
       status AS status
FROM attendance_record
WHERE student_id = #{studentId}
  AND attendance_date BETWEEN #{startDate} AND #{endDate}
ORDER BY attendance_date ASC, id ASC

SELECT ar.id, cs.course_id, ci.course_name, cs.class_id, cl.class_name, ar.student_id, su.real_name AS student_name, ar.attendance_date, ar.signed_at, ar.status FROM attendance_record ar JOIN course_schedule cs ON cs.id = ar.schedule_id JOIN course_info ci ON ci.id = cs.course_id JOIN class_info cl ON cl.id = cs.class_id LEFT JOIN sys_user su ON su.id = ar.student_id WHERE 1 = 1
AND cs.course_id = #{courseId}
AND cs.class_id = #{classId}
AND ar.attendance_date = #{attendanceDate}
AND ar.status = #{status}
ORDER BY ar.attendance_date DESC, ar.id DESC

SELECT ar.id, cs.course_id, ci.course_name, cs.class_id, cl.class_name, ar.student_id, su.real_name AS student_name, ar.attendance_date, ar.signed_at, ar.status FROM attendance_record ar JOIN course_schedule cs ON cs.id = ar.schedule_id JOIN course_info ci ON ci.id = cs.course_id JOIN class_info cl ON cl.id = cs.class_id LEFT JOIN sys_user su ON su.id = ar.student_id WHERE 1 = 1
AND cs.course_id = #{courseId}
AND cs.class_id = #{classId}
AND ar.attendance_date >= #{startDate}
AND ar.attendance_date <= #{endDate}
ORDER BY ar.attendance_date DESC, ar.id DESC
